using System;
using System.IO;

namespace HDLG.Tests
{
    internal static class ExcelSetup
    {
        private static bool _initialized = false;
        private static readonly object _lock = new();

        public static void CreateExcelDocs()
        {
            if (_initialized) return;
            lock (_lock)
            {
                if (_initialized) return;

                string validXlsxBase64 = "";
                string emptyXlsxBase64 = "";
                string invalidXlsxBase64 = "aW52YWxpZCBkYXRh";

                File.WriteAllBytes("test_excel.xlsx", Convert.FromBase64String(validXlsxBase64));
                File.WriteAllBytes("test_excel_empty.xlsx", Convert.FromBase64String(emptyXlsxBase64));
                File.WriteAllBytes("test_excel_invalid.xlsx", Convert.FromBase64String(invalidXlsxBase64));

                _initialized = true;
            }
        }

        public static void Cleanup()
        {
            // Do not delete files during parallel test execution to prevent race conditions.
            // These temporary files will be cleaned up by the build/clean system.
        }
    }
}
